 24	
 25	import { printableVMStatus } from '../../../../../utils';
 26	import IndicationLabelList from '../../../snapshots/components/IndicationLabel/IndicationLabelList';
 27	
 28	import SnapshotDeleteModal from './component/SnapshotDeleteModal';
 29	import { icon } from './utils/snapshotStatus';
 30	
 31	import './virtual-machines-overview-tab-snapshots.scss';
 32	
 33	type VirtualMachinesOverviewTabSnapshotsRowProps = {
 34	  snapshot: V1beta1VirtualMachineSnapshot;
 35	  vm: V1VirtualMachine;
 36	};
 37	
 38	const VirtualMachinesOverviewTabSnapshotsRow: FC<VirtualMachinesOverviewTabSnapshotsRowProps> = ({
 39	  snapshot,
 40	  vm,
 41	}) => {
 42	  const { t } = useKubevirtTranslation();
 43	  const [isKebabOpen, setIsKebabOpen] = useState(false);
 44	  const { createModal } = useModal();
 45	
 46	  const timestamp = timestampFor(
 47	    new Date(snapshot?.metadata?.creationTimestamp),
 48	    new Date(Date.now()),
 49	    false,
 50	  );
 51	
 52	  const Icon = icon[snapshot?.status?.phase];
 53	
 54	  const onToggle = () => setIsKebabOpen((prevIsOpen) => !prevIsOpen);
 55	
 56	  return (
 57	    <div className="VirtualMachinesOverviewTabSnapshotsRow--main">
 58	      <div className="name">
 59	        <Icon />
 60	        <DescriptionListTermHelpText className="pf-v6-c-description-list__term">
 61	          <Popover
 62	            bodyContent={
 63	              <DescriptionList className="pf-v6-c-description-list" isHorizontal>
 64	                <VirtualMachineDescriptionItem
 65	                  descriptionData={
 66	                    <>
 67	                      <Icon />
 68	                      <span className="icon-spacer">{snapshot?.status?.phase}</span>
 69	                    </>
 70	                  }
 71	                  descriptionHeader={t('Status')}
 72	                />
 73	                <VirtualMachineDescriptionItem
 74	                  descriptionData={timestamp}
 75	                  descriptionHeader={t('Created')}
 76	                />
 77	                <VirtualMachineDescriptionItem
 78	                  descriptionData={<IndicationLabelList snapshot={snapshot} />}
 79	                  descriptionHeader={t('Indications')}
 80	                />
 81	              </DescriptionList>
 82	            }
 83	            headerContent={snapshot?.metadata?.name}
 84	            position={PopoverPosition.left}
 85	          >
 86	            <DescriptionListTermHelpTextButton
 87	              className={classnames('pf-v6-c-description-list__text', 'icon-spacer__offset')}
 88	            >
 89	              {snapshot?.metadata?.name}
 90	            </DescriptionListTermHelpTextButton>
 91	          </Popover>
 92	        </DescriptionListTermHelpText>
 93	        <span className="text-muted timestamp">{`(${timestamp})`}</span>
 94	      </div>
 95	      <Dropdown
 96	        isOpen={isKebabOpen}
 97	        onOpenChange={(open: boolean) => setIsKebabOpen(open)}
 98	        onSelect={() => setIsKebabOpen(false)}
 99	        popperProps={{ position: 'right' }}
100	        toggle={KebabToggle({ isExpanded: isKebabOpen, onClick: onToggle })}
101	      >
102	        <DropdownList>
103	          <DropdownItem
104	            isDisabled={vm?.status?.printableStatus !== printableVMStatus.Stopped}
105	            key="restore"
106	            onClick={() => createModal((props) => <RestoreModal snapshot={snapshot} {...props} />)}
107	          >
108	            {t('Restore')}
109	          </DropdownItem>
110	          <DropdownItem
111	            onClick={() =>
112	              createModal((props) => <SnapshotDeleteModal snapshot={snapshot} {...props} />)
113	            }
114	            key="delete"
115	          >
116	            {t('Delete')}
117	          </DropdownItem>
118	        </DropdownList>
119	      </Dropdown>
120	    </div>
121	  );
122	};
123	
124	export default VirtualMachinesOverviewTabSnapshotsRow;

